onClick:
{{
  (() => {

    const norm = s =>
      (s || "")
        .trim()
        .normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "")
        .toLowerCase();

    const newName = inpPLAddName.text;

    const exists = getPicklistItems.data.some(
      item =>
        item.name &&
        norm(item.name) === norm(newName)
    );

    if (exists) {

      showAlert('Name already exists in this list', 'warning');

    } else {

      addPicklistItems.run()
        .then(() => getPicklistItems.run())
        .then(() => resetWidget('inpPLAddName'))
        .then(() => closeModal('mdlPLAdd'));

    }

  })()
}}
